                            <div>
                                <h4 class="text-xs font-black text-indigo-700 uppercase tracking-widest mb-0.5">Detergenza</h4>
                                <p class="text-base text-slate-500 leading-relaxed">Uso coordinato di tensioattivi anionici e cationici.</p>
                            </div>
